import type { ScaleOrdinal, ScaleQuantize, ScaleThreshold } from 'd3-scale';
import { isUndefined } from 'lodash-es';
import { useContext } from 'react';

import { useMapConfig } from './use-map-config.js';
import { ColorScaleContext } from '../contexts/color-scale.context.js';
import {
  isSequentialLegend,
  isThresholdLegend,
} from '../utils/build-scale-from-legend-config.js';

export function useColorScale():
  | ScaleQuantize<string>
  | ScaleThreshold<number, string>
  | ScaleOrdinal<string, string>
  | undefined {
  const context = useContext<
    | ScaleQuantize<string>
    | ScaleThreshold<number, string>
    | ScaleOrdinal<string, string>
    | undefined
  >(ColorScaleContext);
  const { legend } = useMapConfig();

  if (isUndefined(legend) || isUndefined(context)) {
    return undefined;
  }

  if (isSequentialLegend(legend)) {
    return context as ScaleQuantize<string>;
  } else if (isThresholdLegend(legend)) {
    return context as ScaleThreshold<number, string>;
  } else {
    return context as ScaleOrdinal<string, string>;
  }
}
